import sys
from collections import deque

class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def burnTree(self, root: TreeNode, target: int) -> int:
        if not root:
            return 0

        parent = {}
        stack = [root]
        nodes = {}
        while stack:
            node = stack.pop()
            nodes[node.val] = node
            if node.left:
                parent[node.left.val] = node.val
                stack.append(node.left)
            if node.right:
                parent[node.right.val] = node.val
                stack.append(node.right)

        target_node = nodes[target]
        queue = deque([target_node.val])
        burned = {target_node.val}
        steps = 0
        while queue:
            size = len(queue)
            for _ in range(size):
                current = queue.popleft()
                if current in parent and parent[current] not in burned:
                    queue.append(parent[current])
                    burned.add(parent[current])
                if current in nodes:
                    node = nodes[current]
                    if node.left and node.left.val not in burned:
                        queue.append(node.left.val)
                        burned.add(node.left.val)
                    if node.right and node.right.val not in burned:
                        queue.append(node.right.val)
                        burned.add(node.right.val)
            steps += 1
            if not queue:
                break
        return steps - 1

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        nodes = [None] * n
        for i in range(n):
            val, left, right = int(next(it)), int(next(it)), int(next(it))
            node = TreeNode(val)
            nodes[i] = node
            if left != -1:
                node.left = nodes[left]
            if right != -1:
                node.right = nodes[right]
        target = int(next(it))
    except StopIteration:
        sys.exit(0)
    root = next((node for node in nodes if node), None)
    sol = Solution()
    ans = sol.burnTree(root, target)
    print(ans)

