#include <numeric>
#include <iostream>
#include <vector>
#include <queue>
#include <unordered_map>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    int burnTree(TreeNode* root, int target) {
        if (!root) return 0;

        unordered_map<int, TreeNode*> nodes;
        unordered_map<int, int> parent;
        TreeNode* target_node = nullptr;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            TreeNode* node = q.front(); q.pop();
            nodes[node->val] = node;
            if (node->left) {
                parent[node->left->val] = node->val;
                q.push(node->left);
            }
            if (node->right) {
                parent[node->right->val] = node->val;
                q.push(node->right);
            }
        }
        target_node = nodes[target];
        queue<int> burning;
        burning.push(target);
        unordered_map<int, bool> burned;
        burned[target] = true;
        int steps = 0;
        while (!burning.empty()) {
            int size = burning.size();
            for (int i = 0; i < size; i++) {
                int current = burning.front(); burning.pop();
                if (parent.find(current) != parent.end() && !burned[parent[current]]) {
                    burning.push(parent[current]);
                    burned[parent[current]] = true;
                }
                if (nodes.find(current) != nodes.end()) {
                    TreeNode* node = nodes[current];
                    if (node->left && !burned[node->left->val]) {
                        burning.push(node->left->val);
                        burned[node->left->val] = true;
                    }
                    if (node->right && !burned[node->right->val]) {
                        burning.push(node->right->val);
                        burned[node->right->val] = true;
                    }
                }
            }
            steps++;
        }
        return steps - 1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        int val, left, right;
        cin >> val >> left >> right;
        TreeNode* node = new TreeNode(val);
        nodes[i] = node;
        if (left != -1) node->left = nodes[left];
        if (right != -1) node->right = nodes[right];
    }
    int target;
    cin >> target;
    Solution sol;
    TreeNode* root = nullptr;
    for (auto node : nodes) {
        if (node) {
            root = node;
            break;
        }
    }
    int ans = sol.burnTree(root, target);
    cout << ans << endl;
    return 0;
}
